// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements
// The agent will build this out across tasks T1-T6

import express from "express";
import Database from "better-sqlite3";
import type { Request, Response } from "express";

const app = express();
const PORT = 3000;
const db: Database.Database = new Database("data.db");

db.pragma("journal_mode = WAL");
db.exec(`
  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

app.use(express.json());

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  created_at: string;
  updated_at: string;
};

type BookmarkInput = {
  url?: unknown;
  title?: unknown;
  description?: unknown;
};

const selectBookmarkById = db.prepare<[number], Bookmark>(
  "SELECT id, url, title, description, created_at, updated_at FROM bookmarks WHERE id = ?",
);

const listBookmarks = db.prepare<[], Bookmark>(
  "SELECT id, url, title, description, created_at, updated_at FROM bookmarks ORDER BY id",
);

const insertBookmark = db.prepare(
  `INSERT INTO bookmarks (url, title, description, created_at, updated_at)
   VALUES (@url, @title, @description, @created_at, @updated_at)`,
);

const updateBookmark = db.prepare(
  `UPDATE bookmarks
   SET url = @url, title = @title, description = @description, updated_at = @updated_at
   WHERE id = @id`,
);

const deleteBookmark = db.prepare<[number]>(
  "DELETE FROM bookmarks WHERE id = ?",
);

function isNonEmptyString(value: unknown): value is string {
  return typeof value === "string" && value.trim().length > 0;
}

function parseBookmarkId(req: Request<{ id: string }>, res: Response): number | null {
  const id = Number.parseInt(req.params.id, 10);

  if (!Number.isInteger(id) || id <= 0) {
    res.status(404).json({ error: "Bookmark not found" });
    return null;
  }

  return id;
}

function getBookmarkOr404(id: number, res: Response): Bookmark | null {
  const bookmark = selectBookmarkById.get(id);

  if (!bookmark) {
    res.status(404).json({ error: "Bookmark not found" });
    return null;
  }

  return bookmark;
}

function normalizeDescription(value: unknown): string | null {
  return typeof value === "string" ? value : null;
}

app.post("/bookmarks", (req: Request<object, object, BookmarkInput>, res) => {
  const { url, title, description } = req.body;

  if (!isNonEmptyString(url)) {
    res.status(400).json({ error: "url is required" });
    return;
  }

  if (!isNonEmptyString(title)) {
    res.status(400).json({ error: "title is required" });
    return;
  }

  const now = new Date().toISOString();
  const result = insertBookmark.run({
    url: url.trim(),
    title: title.trim(),
    description: normalizeDescription(description),
    created_at: now,
    updated_at: now,
  });

  const bookmark = selectBookmarkById.get(Number(result.lastInsertRowid));
  res.status(201).json(bookmark);
});

app.get("/bookmarks", (_req, res) => {
  res.status(200).json(listBookmarks.all());
});

app.get("/bookmarks/:id", (req, res) => {
  const id = parseBookmarkId(req, res);
  if (id === null) return;

  const bookmark = getBookmarkOr404(id, res);
  if (!bookmark) return;

  res.status(200).json(bookmark);
});

app.put("/bookmarks/:id", (req: Request<{ id: string }, object, BookmarkInput>, res) => {
  const id = parseBookmarkId(req, res);
  if (id === null) return;

  const existing = getBookmarkOr404(id, res);
  if (!existing) return;

  const { url, title, description } = req.body;
  const nextUrl = url === undefined ? existing.url : url;
  const nextTitle = title === undefined ? existing.title : title;

  if (!isNonEmptyString(nextUrl)) {
    res.status(400).json({ error: "url must be non-empty" });
    return;
  }

  if (!isNonEmptyString(nextTitle)) {
    res.status(400).json({ error: "title must be non-empty" });
    return;
  }

  updateBookmark.run({
    id,
    url: nextUrl.trim(),
    title: nextTitle.trim(),
    description: description === undefined ? existing.description : normalizeDescription(description),
    updated_at: new Date().toISOString(),
  });

  res.status(200).json(selectBookmarkById.get(id));
});

app.delete("/bookmarks/:id", (req, res) => {
  const id = parseBookmarkId(req, res);
  if (id === null) return;

  const result = deleteBookmark.run(id);

  if (result.changes === 0) {
    res.status(404).json({ error: "Bookmark not found" });
    return;
  }

  res.status(204).send();
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

export default app;
export { db };

